						function seribu($totalharga){
							$totalharga=ceil($totalharga);
							
							if($totalharga > 999){
								if (substr($totalharga,-3)>499){
									$total_harga=round($totalharga,-3);
								} else {
									$total_harga=round($totalharga,-3)+0;
								} 
							}  else {
								$total_harga=0;
							}
							return number_format($total_harga);
						}
						function seribu2($totalharga){
							$totalharga=ceil($totalharga);
							
							if($totalharga > 999){
								if (substr($totalharga,-3)>499){
									$total_harga=round($totalharga,-3);
								} else {
									$total_harga=round($totalharga,-3)+0;
								} 
							}  else {
								$total_harga=0;
							}
							return $total_harga;
						}
					?>
					
